316→          );
317→        }
318→        const classified = classifyBySimilarity(candidates);
319→
320→        function toUpdateItem(change: ClassifiedChange) {
321→          return {
322→            entity_id: change.id,
323→            entity_type: change.table,
324→            change_description: change.text,
325→            similarity: change.similarity,
326→            level: (change.classification === "urgent-context" ? "urgent" : "update") as "urgent" | "update",
327→          };
328→        }
329→
330→        urgentUpdates = classified
331→          .filter((c) => c.classification === "urgent-context")
332→          .map(toUpdateItem);
333→        contextUpdates = classified
334→          .filter((c) => c.classification === "context-update")
335→          .map(toUpdateItem);
336→      } catch (error) {
337→        log.warn("mcp.intent-context.recent-changes-failed", "Failed to search recent changes", {
338→          error: error instanceof Error ? error.message : String(error),
339→        });
340→      }
341→
342→      log.info("mcp.intent-context.resolved", "Intent context resolved", {
343→        workspaceId, level: result.level,
344→        urgentCount: urgentUpdates.length, contextCount: contextUpdates.length,
345→      });
346→      return jsonResponse({ ...result, urgent_updates: urgentUpdates, context_updates: contextUpdates }, 200);
