  1→/**
  2→ * Context Injector -- Pure functions for brain-context injection
  3→ *
  4→ * Responsible for:
  5→ * 1. Ranking context candidates by weighted cosine similarity
  6→ * 2. Selecting top N within token budget
  7→ * 3. Building <brain-context> XML block
  8→ * 4. Injecting into system prompt (string or array form)
  9→ *
 10→ * All functions are pure -- no IO, no side effects.
 11→ * The orchestration (embedding, cache, DB queries) lives in the proxy route.
 12→ */
 13→import { RecordId } from "surrealdb";
 14→import { cosineSimilarity } from "../graph/embeddings";
 15→
 16→// ---------------------------------------------------------------------------
 17→// Types
 18→// ---------------------------------------------------------------------------
 19→
 20→export type ContextCandidate = {
 21→  readonly id: string;
 22→  readonly type: "decision" | "learning" | "observation";
 23→  readonly text: string;
 24→  readonly embedding?: number[];
 25→  readonly weight: number;
 26→};
 27→
 28→export type RankedCandidate = {
 29→  readonly id: string;
 30→  readonly type: "decision" | "learning" | "observation";
 31→  readonly text: string;
 32→  readonly score: number;
 33→};
 34→
 35→export type InjectionResult = {
 36→  readonly system: string | Array<{ type: string; text: string; cache_control?: { type: string } }>;
 37→  readonly injected: boolean;
 38→  readonly tokensEstimated: number;
 39→  readonly decisionsCount: number;
 40→  readonly learningsCount: number;
 41→  readonly observationsCount: number;
 42→};
 43→
 44→type SystemPrompt = string | Array<{ type: string; text: string; cache_control?: { type: string } }> | undefined;
 45→
 46→// ---------------------------------------------------------------------------
 47→// Recent Changes Types (04-01: vector search classification)
 48→// ---------------------------------------------------------------------------
 49→
 50→export type RecentChangeCandidate = {
 51→  readonly id: string;
 52→  readonly table: "decision" | "task" | "observation";
 53→  readonly text: string;
 54→  readonly similarity: number;
 55→  readonly updatedAt: string;
 56→};
 57→
 58→export type ClassifiedChange = RecentChangeCandidate & {
 59→  readonly classification: "urgent-context" | "context-update";
 60→};
 61→
 62→// ---------------------------------------------------------------------------
 63→// Token Estimation (pure, ~4 chars per token)
 64→// ---------------------------------------------------------------------------
 65→
 66→export function estimateTokenCount(text: string): number {
 67→  return Math.ceil(text.length / 4);
 68→}
 69→
 70→// ---------------------------------------------------------------------------
 71→// Ranking: weighted cosine similarity
 72→// ---------------------------------------------------------------------------
 73→
 74→export function rankCandidates(
 75→  candidates: ContextCandidate[],
 76→  queryEmbedding: number[],
 77→): RankedCandidate[] {
 78→  return candidates
 79→    .map((c) => {
 80→      const hasEmbedding = c.embedding !== undefined && c.embedding.length > 0;
 81→      const score = hasEmbedding
 82→        ? cosineSimilarity(c.embedding!, queryEmbedding) * c.weight
 83→        : c.weight * 0.5;
 84→      return { id: c.id, type: c.type, text: c.text, score };
 85→    })
 86→    .sort((a, b) => b.score - a.score);
 87→}
 88→
 89→// ---------------------------------------------------------------------------
 90→// Budget Selection: top N within token budget
 91→// ---------------------------------------------------------------------------
 92→
 93→export function selectWithinBudget(
 94→  ranked: RankedCandidate[],
 95→  tokenBudget: number,
 96→): RankedCandidate[] {
 97→  const selected: RankedCandidate[] = [];
 98→  let tokensUsed = 0;
 99→
100→  for (const candidate of ranked) {
101→    const candidateTokens = estimateTokenCount(candidate.text);
102→    if (tokensUsed + candidateTokens > tokenBudget) break;
103→    selected.push(candidate);
104→    tokensUsed += candidateTokens;
105→  }
106→
107→  return selected;
108→}
109→
110→// ---------------------------------------------------------------------------
111→// XML Block Construction
112→// ---------------------------------------------------------------------------
113→
114→export function buildBrainContextXml(selected: RankedCandidate[]): string {
115→  if (selected.length === 0) return "";
116→
117→  const decisions = selected.filter((c) => c.type === "decision");
118→  const learnings = selected.filter((c) => c.type === "learning");
119→  const observations = selected.filter((c) => c.type === "observation");
120→
121→  const sections: string[] = [];
122→
123→  if (decisions.length > 0) {
124→    const items = decisions.map((d) => `  <item>${d.text}</item>`).join("\n");
125→    sections.push(`<decisions>\n${items}\n</decisions>`);
126→  }
127→
128→  if (learnings.length > 0) {
129→    const items = learnings.map((l) => `  <item>${l.text}</item>`).join("\n");
130→    sections.push(`<learnings>\n${items}\n</learnings>`);
131→  }
132→
133→  if (observations.length > 0) {
134→    const items = observations.map((o) => `  <item>${o.text}</item>`).join("\n");
135→    sections.push(`<observations>\n${items}\n</observations>`);
136→  }
137→
138→  return `<brain-context>\n${sections.join("\n")}\n</brain-context>`;
139→}
140→
141→// ---------------------------------------------------------------------------
142→// System Prompt Injection
143→// ---------------------------------------------------------------------------
144→
145→export function injectBrainContext(
146→  originalSystem: SystemPrompt,
147→  brainContextXml: string,
148→): InjectionResult {
149→  if (!brainContextXml) {
150→    return {
151→      system: originalSystem ?? "",
152→      injected: false,
153→      tokensEstimated: 0,
154→      decisionsCount: 0,
155→      learningsCount: 0,
156→      observationsCount: 0,
157→    };
158→  }
159→
160→  const tokensEstimated = estimateTokenCount(brainContextXml);
161→
162→  // Count items in XML (by counting <item> tags per section)
163→  const decisionsCount = (brainContextXml.match(/<decisions>[\s\S]*?<\/decisions>/)?.[0]?.match(/<item>/g) ?? []).length;
164→  const learningsCount = (brainContextXml.match(/<learnings>[\s\S]*?<\/learnings>/)?.[0]?.match(/<item>/g) ?? []).length;
165→  const observationsCount = (brainContextXml.match(/<observations>[\s\S]*?<\/observations>/)?.[0]?.match(/<item>/g) ?? []).length;
166→
167→  if (Array.isArray(originalSystem)) {
168→    // Array-form: append brain-context as additional text block with cache_control: ephemeral
169→    const enriched = [
170→      ...originalSystem,
171→      {
172→        type: "text",
173→        text: brainContextXml,
174→        cache_control: { type: "ephemeral" },
175→      },
176→    ];
177→
178→    return {
179→      system: enriched,
180→      injected: true,
181→      tokensEstimated,
182→      decisionsCount,
183→      learningsCount,
184→      observationsCount,
185→    };
186→  }
187→
188→  if (typeof originalSystem === "string") {
189→    // String-form: append brain-context after original text
190→    return {
191→      system: `${originalSystem}\n\n${brainContextXml}`,
192→      injected: true,
193→      tokensEstimated,
194→      decisionsCount,
195→      learningsCount,
196→      observationsCount,
197→    };
198→  }
199→
200→  // No original system prompt: use brain-context as system prompt

200→  // No original system prompt: use brain-context as system prompt
201→  return {
202→    system: brainContextXml,
203→    injected: true,
204→    tokensEstimated,
205→    decisionsCount,
206→    learningsCount,
207→    observationsCount,
208→  };
209→}
