312→// ---------------------------------------------------------------------------
313→// Recent Changes Classification (04-01: pure)
314→// ---------------------------------------------------------------------------
315→
316→const URGENT_CONTEXT_THRESHOLD = 0.85;
317→const CONTEXT_UPDATE_THRESHOLD = 0.65;
318→
319→/**
320→ * Classifies KNN search results by similarity into urgent-context or context-update.
321→ *
322→ * - >= 0.85 similarity -> urgent-context (agent should act on this immediately)
323→ * - >= 0.65 similarity -> context-update (background awareness)
324→ * - < 0.65 similarity  -> filtered out (not relevant)
325→ *
326→ * Preserves input order for candidates that pass the threshold.
327→ */
328→export function classifyBySimilarity(
329→  candidates: RecentChangeCandidate[],
330→): ClassifiedChange[] {
331→  return candidates
332→    .filter((c) => c.similarity >= CONTEXT_UPDATE_THRESHOLD)
333→    .map((c) => ({
334→      ...c,
335→      classification: c.similarity >= URGENT_CONTEXT_THRESHOLD
336→        ? "urgent-context" as const
337→        : "context-update" as const,
338→    }));
339→}
340→
341→// ---------------------------------------------------------------------------
342→// Recent Changes XML Builder (04-01: pure)
343→// ---------------------------------------------------------------------------
344→
345→/**
346→ * Builds an XML block for recent graph changes classified by urgency.
347→ *
348→ * Output structure:
349→ * <recent-changes>
350→ *   <urgent-context>
351→ *     <item type="decision">Use tRPC for all APIs</item>
352→ *   </urgent-context>
353→ *   <context-update>
354→ *     <item type="task">Implement rate limiting</item>
355→ *   </context-update>
356→ * </recent-changes>
357→ */
358→function escapeXml(text: string): string {
359→  return text
360→    .replace(/&/g, "&amp;")
361→    .replace(/</g, "&lt;")
362→    .replace(/>/g, "&gt;")
363→    .replace(/"/g, "&quot;");
364→}
365→
366→export function buildRecentChangesXml(changes: ClassifiedChange[]): string {
367→  if (changes.length === 0) return "";
368→
369→  const urgent = changes.filter((c) => c.classification === "urgent-context");
370→  const updates = changes.filter((c) => c.classification === "context-update");
371→
372→  const sections: string[] = [];
373→
374→  if (urgent.length > 0) {
375→    const items = urgent
376→      .map((c) => `  <item type="${escapeXml(c.table)}">${escapeXml(c.text)}</item>`)
377→      .join("\n");
378→    sections.push(`<urgent-context>\n${items}\n</urgent-context>`);
379→  }
380→
381→  if (updates.length > 0) {
382→    const items = updates
383→      .map((c) => `  <item type="${escapeXml(c.table)}">${escapeXml(c.text)}</item>`)
384→      .join("\n");
385→    sections.push(`<context-update>\n${items}\n</context-update>`);
386→  }
387→
388→  return `<recent-changes>\n${sections.join("\n")}\n</recent-changes>`;
389→}
