391→// ---------------------------------------------------------------------------
392→// Recent Changes Vector Search (04-01: adapter boundary -- DB side effect)
393→// ---------------------------------------------------------------------------
394→
395→/**
396→ * Port signature for searching recent graph changes by vector similarity.
397→ */
398→export type SearchRecentChanges = (
399→  messageEmbedding: number[],
400→  workspaceId: string,
401→  lastRequestAt: Date,
402→) => Promise<RecentChangeCandidate[]>;
403→
404→type KnnRow = {
405→  id: RecordId;
406→  text: string;
407→  similarity: number;
408→  updated_at: string;
409→  workspace: RecordId;
410→};
411→
412→/**
413→ * Searches for recent graph entity changes relevant to a message embedding.
414→ *
415→ * Uses the two-step KNN pattern required by SurrealDB v3.0 (see CLAUDE.md):
416→ * - Step 1: KNN candidates via HNSW index (no WHERE filter)
417→ * - Step 2: filter by workspace + updated_at > last_request_at
418→ *
419→ * Queries decision, task, and observation tables independently then merges results.
420→ */
421→export function createSearchRecentChanges(
422→  surreal: { query: <T>(sql: string, vars?: Record<string, unknown>) => Promise<T> },
423→): SearchRecentChanges {
424→  return async (
425→    messageEmbedding: number[],
426→    workspaceId: string,
427→    lastRequestAt: Date,
428→  ): Promise<RecentChangeCandidate[]> => {
429→    const workspaceRecord = new RecordId("workspace", workspaceId);
430→    const knnLimit = 20;
431→
432→    // Single round-trip: all three two-step KNN queries combined
433→    // Each table needs LET + SELECT (HNSW index cannot combine with B-tree WHERE)
434→    const results = await surreal.query<[KnnRow[], KnnRow[], KnnRow[], KnnRow[], KnnRow[], KnnRow[]]>(
435→      `LET $dec_candidates = SELECT id, summary AS text, vector::similarity::cosine(embedding, $vec) AS similarity, updated_at, workspace
436→         FROM decision WHERE embedding <|${knnLimit}, COSINE|> $vec;
437→       SELECT * FROM $dec_candidates WHERE workspace = $ws AND updated_at > $since ORDER BY similarity DESC LIMIT $limit;
438→       LET $task_candidates = SELECT id, title AS text, vector::similarity::cosine(embedding, $vec) AS similarity, updated_at, workspace
439→         FROM task WHERE embedding <|${knnLimit}, COSINE|> $vec;
440→       SELECT * FROM $task_candidates WHERE workspace = $ws AND updated_at > $since ORDER BY similarity DESC LIMIT $limit;
441→       LET $obs_candidates = SELECT id, text, vector::similarity::cosine(embedding, $vec) AS similarity, updated_at, workspace
442→         FROM observation WHERE embedding <|${knnLimit}, COSINE|> $vec;
443→       SELECT * FROM $obs_candidates WHERE workspace = $ws AND updated_at > $since ORDER BY similarity DESC LIMIT $limit;`,
444→      { vec: messageEmbedding, ws: workspaceRecord, since: lastRequestAt, limit: knnLimit },
445→    );
446→
447→    // LET statements return at indices 0, 2, 4; SELECT results at 1, 3, 5
448→    function toRecentChangeCandidates(
449→      rows: KnnRow[],
450→      table: RecentChangeCandidate["table"],
451→    ): RecentChangeCandidate[] {
452→      return rows.map((row) => ({
453→        id: (row.id as RecordId).id as string,
454→        table,
455→        text: row.text,
456→        similarity: row.similarity,
457→        updatedAt: row.updated_at,
458→      }));
459→    }
460→
461→    return [
462→      ...toRecentChangeCandidates(results[1] ?? [], "decision"),
463→      ...toRecentChangeCandidates(results[3] ?? [], "task"),
464→      ...toRecentChangeCandidates(results[5] ?? [], "observation"),
465→    ];
466→  };
467→}
