946→      { entity: input.entityRecord, limit: input.limit },
947→    )
948→    .collect<[UnifiedEdgeRow[]]>();
949→
950→  const neighbors: EntityNeighbor[] = [];
951→  const seen = new Set<string>();
952→
953→  for (const row of rows) {
954→    const edgeTable = row.id.table.name;
955→    const relationKind = row.kind ?? edgeTable;
956→    const direction = toRecordIdString(row.in) === toRecordIdString(input.entityRecord) ? "outgoing" : "incoming";
957→    const neighborRecord = direction === "outgoing" ? row.out : row.in;
958→    const key = `${relationKind}:${toRecordIdString(neighborRecord)}`;
959→    if (seen.has(key)) continue;
960→
961→    const scoped = await isEntityInWorkspace(input.surreal, input.workspaceRecord, neighborRecord as GraphEntityRecord);
962→    if (!scoped) continue;
963→
964→    const name = await readEntityName(input.surreal, neighborRecord as GraphEntityRecord);
965→    if (!name) continue;
966→
967→    seen.add(key);
968→    neighbors.push({
969→      id: toRecordIdString(neighborRecord),
970→      kind: neighborRecord.table.name as GraphEntityTable,
971→      name,
972→      relationKind,
973→      direction,
974→      confidence: row.confidence ?? 1.0,
975→    });
976→  }
977→
978→  return neighbors;
979→}
